class SecureLogManager:
    """Manages application logging with rotation and secure file permissions."""

    def __init__(
        self,
        log_dir="logs",
        app_name="myapp",
        max_bytes=10 * 1024 * 1024,  # 10 MB
        backup_count=5,
        log_level=logging.DEBUG,
        file_permission=0o640,
        dir_permission=0o750,
    ):
        self.log_dir = Path(log_dir)
        self.app_name = app_name
        self.max_bytes = max_bytes
        self.backup_count = backup_count
        self.log_level = log_level
        self.file_permission = file_permission
        self.dir_permission = dir_permission
        self.logger = None

        self._setup_log_directory()
        self._configure_logging()

    def _setup_log_directory(self):
        """Create log directory with secure permissions."""
        if not self.log_dir.exists():
            self.log_dir.mkdir(parents=True, exist_ok=True)
        os.chmod(self.log_dir, self.dir_permission)
        print(f"Log directory set up at: {self.log_dir.resolve()}")
        print(f"Directory permissions: {oct(self.dir_permission)}")

    def _set_file_permissions(self, filepath):
        """Set secure file permissions on a log file."""
        if os.path.exists(filepath):
            os.chmod(filepath, self.file_permission)

    def _configure_logging(self):
        """Configure logging with multiple handlers and rotation."""
        self.logger = logging.getLogger(self.app_name)
        self.logger.setLevel(self.log_level)

        # Clear any existing handlers
        self.logger.handlers.clear()

        # Log format
        detailed_format = logging.Formatter(
            fmt="%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(message)s",
            datefmt="%Y-%m-%d %H:%M:%S",
        )
        simple_format = logging.Formatter(
            fmt="%(asctime)s | %(levelname)-8s | %(message)s",
            datefmt="%Y-%m-%d %H:%M:%S",
        )

        # 1. Size-based rotating file handler (general log)
        general_log_path = self.log_dir / f"{self.app_name}.log"
        size_handler = logging.handlers.RotatingFileHandler(
            filename=general_log_path,
            maxBytes=self.max_bytes,
            backupCount=self.backup_count,
            encoding="utf-8",
        )
        size_handler.setLevel(logging.DEBUG)
        size_handler.setFormatter(detailed_format)
        # Override the rotation method to set permissions on rotated files
        original_rotator = size_handler.rotator

        def secure_rotator(source, dest):
            if original_rotator:
                original_rotator(source, dest)
            else:
                os.rename(source, dest)
            self._set_file_permissions(dest)

        size_handler.rotator = secure_rotator
        self.logger.addHandler(size_handler)
        self._set_file_permissions(general_log_path)

        # 2. Time-based rotating file handler (daily log)
        daily_log_path = self.log_dir / f"{self.app_name}_daily.log"
        time_handler = logging.handlers.TimedRotatingFileHandler(
            filename=daily_log_path,
            when="midnight",
            interval=1,
            backupCount=30,  # Keep 30 days
            encoding="utf-8",
        )
        time_handler.setLevel(logging.INFO)
        time_handler.setFormatter(detailed_format)
        time_handler.suffix = "%Y-%m-%d"

        original_time_rotator = time_handler.rotator

        def secure_time_rotator(source, dest):
            if original_time_rotator:
                original_time_rotator(source, dest)
            else:
                os.rename(source, dest)
            self._set_file_permissions(dest)

        time_handler.rotator = secure_time_rotator
        self.logger.addHandler(time_handler)
        self._set_file_permissions(daily_log_path)

        # 3. Error-only file handler
        error_log_path = self.log_dir / f"{self.app_name}_error.log"
        error_handler = logging.handlers.RotatingFileHandler(
            filename=error_log_path,
            maxBytes=self.max_bytes,
            backupCount=self.backup_count * 2,  # Keep more error logs
            encoding="utf-8",
        )
        error_handler.setLevel(logging.ERROR)
        error_handler.setFormatter(detailed_format)

        original_error_rotator = error_handler.rotator

        def secure_error_rotator(source, dest):
            if original_error_rotator:
                original_error_rotator(source, dest)
            else:
                os.rename(source, dest)
            self._set_file_permissions(dest)

        error_handler.rotator = secure_error_rotator
        self.logger.addHandler(error_handler)
        self._set_file_permissions(error_log_path)

        # 4. Console handler
        console_handler = logging.StreamHandler(sys.stdout)
        console_handler.setLevel(logging.INFO)
        console_handler.setFormatter(simple_format)
        self.logger.addHandler(console_handler)

        self.logger.info("Logging system initialized successfully")

    def get_logger(self):
        """Return the configured logger."""
        return self.logger

    def verify_permissions(self):
        """Verify and report permissions on all log files."""
        print("\n--- Log File Permissions Report ---")
        for log_file in self.log_dir.iterdir():
            if log_file.is_file():
                file_stat = os.stat(log_file)
                mode = stat.S_IMODE(file_stat.st_mode)
                print(f"  {log_file.name}: {oct(mode)}")

                # Check for overly permissive files
                if mode & stat.S_IROTH or mode & stat.S_IWOTH:
                    self.logger.warning(
                        f"Log file {log_file.name} is world-readable/writable!"
                    )

        dir_stat = os.stat(self.log_dir)
        dir_mode = stat.S_IMODE(dir_stat.st_mode)
        print(f"  Directory ({self.log_dir}): {oct(dir_mode)}")
        print("-----------------------------------\n")

    def cleanup_old_logs(self, max_age_days=90):
        """Remove log files older than max_age_days."""
        import time

        now = time.time()
        cutoff = now - (max_age_days * 86400)
        removed_count = 0

        for log_file in self.log_dir.iterdir():
            if log_file.is_file() and log_file.stat().st_mtime < cutoff:
                self.logger.info(f"Removing old log file: {log_file.name}")
                log_file.unlink()
                removed_count += 1

        self.logger.info(
            f"Cleanup complete. Removed {removed_count} old log files."
        )
        return removed_count


class SampleApplication:
    """Sample application demonstrating the logging system."""

    def __init__(self, logger):
        self.logger = logger
        self.logger.info("SampleApplication initialized")

    def process_data(self, data):
        self.logger.debug(f"Processing data: {data}")
        try:
            if not data:
                raise ValueError("Empty data received")
            result = [item.upper() if isinstance(item, str) else item for item in data]
            self.logger.info(f"Successfully processed {len(data)} items")
            return result
        except (ValueError, AttributeError) as e:
            self.logger.error(f"Error processing data: {e}", exc_info=True)
            return None

    def perform_calculation(self, a, b):
        self.logger.debug(f"Performing calculation: {a} / {b}")
        try:
            result = a / b
            self.logger.info(f"Calculation result: {a} / {b} = {result}")
            return result
        except ZeroDivisionError:
            self.logger.critical(
                "Division by zero attempted!", exc_info=True
            )
            return None

    def simulate_workflow(self):
        """Simulate a typical application workflow with various log levels."""
        self.logger.info("=== Starting workflow simulation ===")

        # Debug messages
        self.logger.debug("Loading configuration...")
        self.logger.debug("Configuration loaded: {db_host: localhost, port: 5432}")

        # Info messages
        self.logger.info("Connecting to database...")
        self.logger.info("Database connection established")

        # Processing
        self.process_data(["hello", "world", "test"])
        self.process_data([])  # This will trigger an error

        # Calculations
        self.perform_calculation(100, 3)
        self.perform_calculation(50, 0)  # This will trigger a critical error

        # Warning
        self.logger.warning("Memory usage is at 85%")
        self.logger.warning("API rate limit approaching: 950/1000 requests")

        # Simulate multiple operations
        for i in range(20):
            self.logger.debug(f"Processing batch item {i + 1}/20")
            if i % 5 == 0:
                self.logger.info(f"Batch progress: {((i + 1) / 20) * 100:.0f}%")

        self.logger.info("=== Workflow simulation complete ===")


